#include <iostream>
#include <string>
#include <vector>

// --- Namespace: GameEngine ---
namespace GameEngine {
    const int VERSION = 1;
    const std::string NAME = "Adventure Engine";

    void initialize() {
        std::cout << "Game Engine initialized (v" << VERSION << ")" << std::endl;
    }

    class Entity {
    private:
        std::string name;
        int id;

    public:
        Entity(const std::string& n, int i) : name(n), id(i) {}

        void display() const {
            std::cout << "Entity: " << name << " (ID: " << id << ")" << std::endl;
        }
    };
}

// --- Namespace: GameLogic ---
namespace GameLogic {
    const int MAX_PLAYERS = 4;

    class Player {
    private:
        std::string name;
        int health;

    public:
        Player(const std::string& n) : name(n), health(100) {}

        void display() const {
            std::cout << "Player: " << name << " (HP: " << health << ")" << std::endl;
        }

        void takeDamage(int damage) {
            health -= damage;
            if (health < 0) health = 0;
        }
    };

    void processTurn(Player& player) {
        std::cout << "Processing turn for " << player.getName() << std::endl;
    }

    // Helper functions (internal)
    namespace Utils {
        int clamp(int value, int min, int max) {
            if (value < min) return min;
            if (value > max) return max;
            return value;
        }
    }
}

// --- Namespace: GameUI ---
namespace GameUI {
    void displayMenu() {
        std::cout << "\n=== Main Menu ===" << std::endl;
        std::cout << "1. Play" << std::endl;
        std::cout << "2. Load" << std::endl;
        std::cout << "3. Settings" << std::endl;
        std::cout << "4. Quit" << std::endl;
    }

    void displayMessage(const std::string& msg) {
        std::cout << "[UI] " << msg << std::endl;
    }
}

// --- Using namespace aliases ---
namespace GE = GameEngine;
namespace GL = GameLogic;

int main() {
    std::cout << "=== Namespaces in Large Projects ===" << std::endl;

    // 1. Using fully qualified names
    std::cout << "\n--- Fully Qualified Names ---" << std::endl;
    GameEngine::initialize();

    GameEngine::Entity hero("Hero", 1);
    hero.display();

    // 2. Using namespace aliases
    std::cout << "\n--- Namespace Aliases ---" << std::endl;
    GL::Player player("Aragorn");
    player.display();

    // 3. Using specific declarations
    std::cout << "\n--- Specific Declarations ---" << std::endl;
    using GameUI::displayMenu;
    displayMenu();

    // 4. Namespace with internal helper
    std::cout << "\n--- Internal Helper ---" << std::endl;
    int clamped = GL::Utils::clamp(150, 0, 100);
    std::cout << "Clamped value: " << clamped << std::endl;

    // 5. Using namespace (careful!)
    std::cout << "\n--- Using Namespace (limited scope) ---" << std::endl;
    {
        using namespace GameLogic;
        Player p2("Legolas");
        p2.display();
        std::cout << "Max players: " << MAX_PLAYERS << std::endl;
    }

    // 6. Nested namespaces
    std::cout << "\n--- Nested Namespace ---" << std::endl;
    GameUI::displayMessage("Welcome to the game!");

    // 7. Namespace conflicts
    std::cout << "\n--- Avoiding Conflicts ---" << std::endl;
    std::cout << "GameEngine::VERSION: " << GE::VERSION << std::endl;
    std::cout << "GameLogic::MAX_PLAYERS: " << GL::MAX_PLAYERS << std::endl;

    std::cout << "\n--- Namespace Best Practices ---" << std::endl;
    std::cout << "✅ Group related code" << std::endl;
    std::cout << "✅ Avoid 'using namespace' in headers" << std::endl;
    std::cout << "✅ Use aliases for long namespaces" << std::endl;
    std::cout << "✅ Keep namespaces focused" << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>

namespace Game {
    void start() { std::cout << "Game started" << std::endl; }
}

namespace Game {  // Same namespace, different file
    void load() { std::cout << "Game loaded" << std::endl; }
}

int main() {
    Game::start();
    Game::load();
    return 0;
}

phase2.explanation:
Namespaces can be reopened, but this can be confusing.

**Better:**
```cpp
namespace Game {
    void start() { std::cout << "Game started" << std::endl; }
    void load() { std::cout << "Game loaded" << std::endl; }
}
```

**PlusPlus-chan says:**
"Group related functions in one namespace declaration. Reopening namespaces is allowed but can be confusing."

phase3.solution:
#include <iostream>
#include <string>

namespace Graphics {
    void draw() {
        std::cout << "Drawing..." << std::endl;
    }

    void clear() {
        std::cout << "Clearing screen..." << std::endl;
    }
}

namespace Audio {
    void playSound(const std::string& sound) {
        std::cout << "Playing: " << sound << std::endl;
    }

    void stopAll() {
        std::cout << "Stopping all sounds" << std::endl;
    }
}

// Aliases
namespace G = Graphics;
namespace A = Audio;

int main() {
    std::cout << "=== Namespaces Demo ===" << std::endl;

    std::cout << "\n--- Fully Qualified ---" << std::endl;
    Graphics::draw();
    Graphics::clear();
    Audio::playSound("bgm.mp3");
    Audio::stopAll();

    std::cout << "\n--- Aliases ---" << std::endl;
    G::draw();
    G::clear();
    A::playSound("sfx.wav");
    A::stopAll();

    std::cout << "\n--- Using Declarations ---" << std::endl;
    using Graphics::draw;
    using Audio::playSound;

    draw();
    playSound("ambient.mp3");

    return 0;
}
